CREATE TABLE products (id SERIAL PRIMARY KEY, name TEXT NOT NULL, price DECIMAL NOT NULL, category TEXT, desc TEXT, images TEXT[], code TEXT, stock BOOLEAN DEFAULT TRUE, created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()); CREATE TABLE categories (id SERIAL PRIMARY KEY, name TEXT UNIQUE NOT NULL); CREATE TABLE staff (id SERIAL PRIMARY KEY, full_name TEXT NOT NULL, first_name TEXT NOT NULL, login TEXT UNIQUE NOT NULL);